sql:
SELECT COUNT(combat_log_id) AS total_combat_logs
  FROM combat_logs
  WHERE character_id = 123;

external_knowledge:
- "embarked on more than 100 hours of adventure" refers to characters with a total playtime greater than 100 hours;
- "faced at least 10 battles" refers to characters with at least 10 combats recorded;
- "ranked by their user's playtime and experience points" means the characters are ranked within each user's account based on their total playtime and total experience points earned.
